var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"우리 역시 창칼로 우리가 옳다고 믿는 뜻을 관철하는 자들이다.","JPN":"我々も槍や剣を持ち、我々が正しいと信じた意思を貫く者たちだ。","ENG":"In the end, we too use our blades for the sake of what we believe to be right.","TWN":"我們也是用刀劍貫徹我們信念的人。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"그러니 나를 넘어서 가라.","JPN":"だからこれ以上進むのならば、私を越えて行きたまえ。","ENG":"So if you must go, go through me.","TWN":"所以，超越我吧。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"이 너머에, 그대가 진정으로 옳다고 믿는 길이 있다면!","JPN":"この向こうに、君が心から正しいと信じる道があるのなら。","ENG":"If the path you truly believe is right lies beyond here, that is!","TWN":"如果你真的堅信，正確的道路就在我後方的話！"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_B","text":{"KOREA":"광대라는 기록은 데이터베이스에서 삭제해야겠군! 이래서 휴먼들의 평은 신뢰할 수가 없어!","JPN":"道化という記録はデータベースから削除しなければなりませんね。これだからヒューマンの評価は信頼できません。","ENG":"I should delete your description of being a clown from my database! This is why I find human assessment of each other so unreliable!","TWN":"看來要從資料庫刪除你是個小丑的記錄。所以我就說，不能信賴人類的評價！"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저건…… 뭘 하는 거지?","JPN":"あれは……何だ？","ENG":"What... on earth are they doing?","TWN":"那個是……你在做什麼呢？"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"호라이즌 언니가 보여준 <color=#ffd34c>호라이즌 명작선</color>을 따라하는 거예요.","JPN":"ホライズンお姉ちゃんが見せてくれた<color=#ffd34c>ホライズン名作選</color>の真似です。","ENG":"They're reenacting <color=#ffd34c>Horizon's Greatest Hits</color> that Horizon showed them.","TWN":"我在模仿地平線姊姊展示的<color=#ffd34c>地平線名著選</color>。"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"언니가 여기 오실 때면 굉장한 걸 보여주겠다면서 여러 영상을 보여주시거든요.","JPN":"お姉ちゃんはここに来るたびに、すごいものがあるって色んな動画を見せてくれるんです。","ENG":"Every time she visits, she plays a bunch of videos saying she's gonna show something epic.","TWN":"姊姊來的時候，總是給我看各種影片，說要給我看一些很厲害的東西。"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"레이첼 언니는 애들한테 뭘 그런 걸 보여주냐며 화내지만, 넷튜브보다 흥미진진해서 애들한테 인기가 많아요.","JPN":"レイチェルお姉ちゃんは子どもたちに見せるものじゃないって怒るけど、ネットチューブよりも面白いから大人気なんですよ。","ENG":"Rachel always scolds her for showing the kids stuff like that, but they find it way more fun than NetTube.","TWN":"雖然瑞秋姊姊總是生氣地說不應該給孩子們看這些東西，但比起網路劇，這些內容更有趣，所以很受孩子們歡迎。"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"저는 특히, 기사님이 버고 소드로 땅을 가르는 장면이 인상깊었어요!","JPN":"私は特に、騎士様がヴァルゴソードで大地を切り裂く場面が印象的でした！","ENG":"Personally, I loved the scene where you split the ground with the Virgo Sword!","TWN":"我尤其對騎士用巨劍劈開大地的場景印象深刻！"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……그게 용케 나인 걸 알아챘군.","JPN":"……よく私だとわかったな。","ENG":"...So you figured out it was me.","TWN":"……原來你能察覺到那是我啊。"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"저, 저도 처음엔 긴가민가했는데, 원장님 도움으로 기사님을 옮기던 도중 태스크포스 명함을 발견했거든요","JPN":"わ、私も最初は自信なかったけど、院長先生のお手伝いで騎士様を運んでたら、タスクフォースの名刺を見つけて。","ENG":"I-I wasn't sure at first, but while we were helping move you, the headmaster and I found your TASKFORCE card.","TWN":"我，我一開始也半信半疑，但在院長的幫助下移動騎士時發現了特遣勢力的名片。"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"죄송해요! 소지품을 뒤지려던 건 아니었어요!","JPN":"すみません！　持ち物を漁るつもりじゃなかったんです！","ENG":"I'm sorry! I wasn't trying to snoop through your stuff!","TWN":"很抱歉！我不是故意要翻你東西的！"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮다. 도움을 받은 건 내 쪽이니까.","JPN":"問題ない。助けてもらったのはこちらの方だ。","ENG":"It's fine. I'm the one who owes you.","TWN":"沒關係，因為是我這邊得到了幫助。"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"진료비는…….","JPN":"治療代は……","ENG":"As for the medical bill...","TWN":"醫療費用是……"},"stage":{"bg":"ROOFTOP2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"됐습니다. 딱히 돈을 바라고 한 일이 아니에요.","JPN":"いいんです。別にお金が欲しくて助けたわけではありません。","ENG":"No need. I didn't do it for money.","TWN":"好了。我並不是為了錢才做這件事的。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기사단이야말로 비용 문제로 의뢰를 넣지 못하는 난민지구에 무상으로 도움을 주는 태스크포스잖습니까.","JPN":"騎士団こそ、生活が貧しくて依頼が出せない難民地区を無償で助けてくれるタスクフォースではありませんか。","ENG":"Your Order helps the refugee districts for free because they can't afford requests. That's what TASKFORCEs like yours do, right?","TWN":"騎士團才是那個在難民區因為費用問題無法委託的地方提供免費幫助的特遣勢力啊。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"원장님! 오셨어요?","JPN":"先生！　おかえりなさい！","ENG":"Headmaster! You're back?","TWN":"院長！你來了？"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그래. 나 없는 동안 말썽 안 부렸지?","JPN":"ああ、私のいない間大人しくしてたかい？","ENG":"Yes. You kids didn't cause trouble while I was gone, did you?","TWN":"對。我不在的時候沒有惹麻煩吧？"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"죄송합니다. 쟤들은 병원에 입원한 저희 보육원 소속 꼬맹이들인데.","JPN":"すみません。この子たちは病院に入院しているうちの施設の子なのです。","ENG":"My apologies. Those are our orphanage kids who are currently hospitalized.","TWN":"對不起，他們是我們孤兒院的院童。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기사님을 보고 싶다고 하도 칭얼대는 바람에, 어쩌다 보니 여기서 소란을 피우네요.","JPN":"騎士様に会いたいとせがまれて連れてきましたが、騒がしくしてしまいましたね。","ENG":"They kept begging to see you, so things got a little loud over here.","TWN":"因為一直吵著說想見騎士，結果不知不覺就在這裡鬧起來了。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……저 많은 아이들을 혼자서 돌보고 있는 겁니까?","JPN":"……こんなたくさんの子どもを、一人で世話しているのですか？","ENG":"...Are you taking care of all of them on your own?","TWN":"……你一個人照顧那麼多孩子嗎？"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"죽으면 끝인데 돈 모아서 어디다 쓰겠습니까? 애들이 건강하게만 자라면 그만이죠.","JPN":"死んだら終わりなのに、お金なんて集めても仕方がないでしょう。子どもたちが元気に育ってくれれば、それ以上嬉しいことはありません。","ENG":"Can't take it with you, so why save money? All that matters is they grow up healthy.","TWN":"死了就結束了，攢那麼多錢有什麼用呢？只要孩子們健康成長就好了。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"투자받은 목돈도 있으니, 기사님이 신경 쓰실 필요 없습니다.","JPN":"それに、投資してもらった資金もありますし、心配いりませんよ。","ENG":"We've got some investment funds too, so don't worry about it.","TWN":"我們有投資的大筆資金，你不需要操心。"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_A","text":{"KOREA":"있지, 누나! 누나랑 호라이즌이랑 싸우면 진짜 호라이즌이 이겨?","JPN":"ねえ、お姉ちゃん！　お姉ちゃんとホライズンが戦ったら本当にホライズンが勝つの？","ENG":"Miss! If you and Horizon got in a real fight, would she win?","TWN":"那個，姊姊！如果姊姊和地平線打架的話，真的會是地平線贏嗎？"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRINCIPAL_NPC_CHILD_B","text":{"KOREA":"나도 궁금해! 맨날 호라이즌은 자기가 제대로 안 싸워서 밀린 것처럼 보인 거래!","JPN":"私も気になる！　ホライズンはいつも、本気出してないから負けてるように見えるんだって！","ENG":"Yeah! She always says she was holding back last time!","TWN":"我也很好奇！每天都聽說是因為地平線自己沒好好戰鬥才被打敗的！"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"으, 응?","JPN":"う、うん？","ENG":"H-huh?","TWN":"嗯，嗯？"},"stage":{"bg":"ROOFTOP2","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};